You are implementing features for a Blazor Web App (Interactive Auto, Global mode with Individual auth) located at `/tmp/sv-f8e61ba0fb714c36b414d39ce67f98ea/ShipmentTracker/`.

The project structure:
- `ShipmentTracker/` - server project (hosts app, API endpoints, EF Core, Identity)
- `ShipmentTracker.Client/` - client project (all interactive UI components)

## Requirements
- Dispatchers view a list of shipments with status and destination
- Customers check their shipment status and estimated delivery
- Every page has interactive controls
- Auth is already set up (ASP.NET Core Identity with Individual accounts)

## What to implement

### 1. Delete template pages
Delete these files from `ShipmentTracker.Client/Pages/`:
- `Counter.razor`
- `Weather.razor`

### 2. Create shared model in Client project

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime ShippedDate { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

### 3. Create service interface in Client project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task UpdateShipmentStatusAsync(int id, string newStatus);
}
```
(Add the appropriate using for Models namespace)

### 4. Client-side implementation using HttpClient

Create `ShipmentTracker.Client/Services/ShipmentServiceClient.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentServiceClient(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await httpClient.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task UpdateShipmentStatusAsync(int id, string newStatus)
    {
        await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", newStatus);
    }
}
```

### 5. Server-side implementation with seed data

Create `ShipmentTracker/Services/ShipmentServiceServer.cs`:
```csharp
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

public class ShipmentServiceServer : IShipmentService
{
    private static readonly List<Shipment> _shipments =
    [
        new() { Id = 1, TrackingNumber = "TRK-001234", Status = "In Transit", Origin = "New York, US", Destination = "London, UK", EstimatedDelivery = DateTime.Today.AddDays(3), ShippedDate = DateTime.Today.AddDays(-2), CustomerEmail = "alice@example.com", Description = "Electronics - Laptop" },
        new() { Id = 2, TrackingNumber = "TRK-001235", Status = "Delivered", Origin = "Shanghai, CN", Destination = "Los Angeles, US", EstimatedDelivery = DateTime.Today.AddDays(-1), ShippedDate = DateTime.Today.AddDays(-7), CustomerEmail = "bob@example.com", Description = "Furniture - Office Chair" },
        new() { Id = 3, TrackingNumber = "TRK-001236", Status = "Pending Pickup", Origin = "Berlin, DE", Destination = "Tokyo, JP", EstimatedDelivery = DateTime.Today.AddDays(5), ShippedDate = DateTime.Today, CustomerEmail = "carol@example.com", Description = "Automotive Parts" },
        new() { Id = 4, TrackingNumber = "TRK-001237", Status = "In Transit", Origin = "Sydney, AU", Destination = "Mumbai, IN", EstimatedDelivery = DateTime.Today.AddDays(4), ShippedDate = DateTime.Today.AddDays(-1), CustomerEmail = "dave@example.com", Description = "Textiles - Cotton Fabric" },
        new() { Id = 5, TrackingNumber = "TRK-001238", Status = "Customs Hold", Origin = "São Paulo, BR", Destination = "Paris, FR", EstimatedDelivery = DateTime.Today.AddDays(6), ShippedDate = DateTime.Today.AddDays(-3), CustomerEmail = "eve@example.com", Description = "Food Products - Coffee Beans" },
    ];

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateShipmentStatusAsync(int id, string newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
        }
        return Task.CompletedTask;
    }
}
```

### 6. API endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (IShipmentService service) =>
            await service.GetAllShipmentsAsync());

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        });

        group.MapPut("{id}/status", async (int id, string newStatus, IShipmentService service) =>
        {
            await service.UpdateShipmentStatusAsync(id, newStatus);
            return Results.NoContent();
        });
    }
}
```

