                            <dd>
                                @if (shipment.EstimatedDelivery.HasValue)
                                {
                                    <strong class="text-primary fs-5">
                                        @shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")
                                    </strong>
                                    @if (shipment.EstimatedDelivery.Value > DateTime.Today)
                                    {
                                        <br />
                                        <small class="text-muted">
                                            (@((shipment.EstimatedDelivery.Value - DateTime.Today).Days) days remaining)
                                        </small>
                                    }
                                }
                                else
                                {
                                    <span class="text-muted">Not available</span>
                                }
                            </dd>
