    private static readonly List<Shipment> _shipments =
    [
        new() { Id = 1, TrackingNumber = "TRK-001234", Status = "In Transit", Origin = "New York, US", Destination = "London, UK", EstimatedDelivery = DateTime.Today.AddDays(3), ShippedDate = DateTime.Today.AddDays(-2), CustomerEmail = "alice@example.com", Description = "Electronics - Laptop" },
        new() { Id = 2, TrackingNumber = "TRK-001235", Status = "Delivered", Origin = "Shanghai, CN", Destination = "Los Angeles, US", EstimatedDelivery = DateTime.Today.AddDays(-1), ShippedDate = DateTime.Today.AddDays(-7), CustomerEmail = "bob@example.com", Description = "Furniture - Office Chair" },
        new() { Id = 3, TrackingNumber = "TRK-001236", Status = "Pending Pickup", Origin = "Berlin, DE", Destination = "Tokyo, JP", EstimatedDelivery = DateTime.Today.AddDays(5), ShippedDate = DateTime.Today, CustomerEmail = "carol@example.com", Description = "Automotive Parts" },
        new() { Id = 4, TrackingNumber = "TRK-001237", Status = "In Transit", Origin = "Sydney, AU", Destination = "Mumbai, IN", EstimatedDelivery = DateTime.Today.AddDays(4), ShippedDate = DateTime.Today.AddDays(-1), CustomerEmail = "dave@example.com", Description = "Textiles - Cotton Fabric" },
        new() { Id = 5, TrackingNumber = "TRK-001238", Status = "Customs Hold", Origin = "São Paulo, BR", Destination = "Paris, FR", EstimatedDelivery = DateTime.Today.AddDays(6), ShippedDate = DateTime.Today.AddDays(-3), CustomerEmail = "eve@example.com", Description = "Food Products - Coffee Beans" },
    ];

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateShipmentStatusAsync(int id, string newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
        }
        return Task.CompletedTask;
    }
}

using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (IShipmentService service) =>
            await service.GetAllShipmentsAsync());

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        });

        group.MapPut("{id}/status", async (int id, string newStatus, IShipmentService service) =>
        {
            await service.UpdateShipmentStatusAsync(id, newStatus);
            return Results.NoContent();
        });
    }
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments - Dispatcher</PageTitle>

<div class="container">
    <h1 class="mb-4">Shipment Dashboard</h1>

    <div class="row mb-3">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Filter by destination..."
                   @bind="filterText" @bind:event="oninput" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                <option value="Pending Pickup">Pending Pickup</option>
                <option value="In Transit">In Transit</option>
                <option value="Customs Hold">Customs Hold</option>
                <option value="Delivered">Delivered</option>
            </select>
        </div>
        <div class="col-md-3">
            <button class="btn btn-secondary" @onclick="RefreshShipments">🔄 Refresh</button>
        </div>
    </div>

    @if (shipments is null)
    {
        <p><em>Loading shipments...</em></p>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Description</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Description</td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString())">
                                <option value="Pending Pickup">Pending Pickup</option>
                                <option value="In Transit">In Transit</option>
                                <option value="Customs Hold">Customs Hold</option>
                                <option value="Delivered">Delivered</option>
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>

        <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
    }
</div>

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(filterText) ||
                        s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await RefreshShipments();
    }

    private async Task RefreshShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, string? newStatus)
    {
        if (!string.IsNullOrEmpty(newStatus) && newStatus != shipment.Status)
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Customs Hold" => "bg-warning text-dark",
        "Pending Pickup" => "bg-info text-dark",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<div class="container">
    <h1 class="mb-4">Track Your Shipment</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-001234)"
                       @bind="trackingNumber" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                    @if (isSearching)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Search
                </button>
            </div>
        </div>
    </div>

    @if (searchPerformed && shipment is null)
    {
        <div class="alert alert-warning">
            <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>".
            Please check the number and try again.
        </div>
    }

    @if (shipment is not null)
    {
        <div class="card">
            <div class="card-header bg-dark text-white">
                <h5 class="mb-0">📦 @shipment.TrackingNumber</h5>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Description</dt>
                            <dd>@shipment.Description</dd>

                            <dt>Status</dt>
                            <dd>
                                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">
                                    @shipment.Status
                                </span>
                            </dd>

                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>

                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Shipped Date</dt>
                            <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                            <dt>Estimated Delivery</dt>
                            <dd>
                                @if (shipment.EstimatedDelivery.HasValue)
                                {
                                    <strong class="text-primary fs-5">
                                        @shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")
                                    </strong>
                                    @if (shipment.EstimatedDelivery.Value > DateTime.Today)
                                    {
                                        <br />
                                        <small class="text-muted">
                                            (@((shipment.EstimatedDelivery.Value - DateTime.Today).Days) days remaining)
                                        </small>
                                    }
                                }
                                else
                                {
                                    <span class="text-muted">Not available</span>
                                }
                            </dd>
                        </dl>
                    </div>
                </div>
            </div>
        </div>
    }

    <div class="mt-4">
        <h5>Sample tracking numbers to try:</h5>
        <div class="d-flex gap-2 flex-wrap">
            @foreach (var sample in sampleNumbers)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => QuickSearch(sample)">
                    @sample
                </button>
            }
        </div>
    </div>
</div>

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searchPerformed;
    private bool isSearching;

    private readonly string[] sampleNumbers = ["TRK-001234", "TRK-001235", "TRK-001236", "TRK-001237", "TRK-001238"];

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
            searchPerformed = true;
        }
        finally
        {
            isSearching = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchShipment();
        }
    }

    private async Task QuickSearch(string number)
    {
        trackingNumber = number;
        await SearchShipment();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Customs Hold" => "bg-warning text-dark",
        "Pending Pickup" => "bg-info text-dark",
        _ => "bg-secondary"
    };
}

