@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments - Dispatcher</PageTitle>

<div class="container">
    <h1 class="mb-4">Shipment Dashboard</h1>

    <div class="row mb-3">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Filter by destination..."
                   @bind="filterText" @bind:event="oninput" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                <option value="Pending Pickup">Pending Pickup</option>
                <option value="In Transit">In Transit</option>
                <option value="Customs Hold">Customs Hold</option>
                <option value="Delivered">Delivered</option>
            </select>
        </div>
        <div class="col-md-3">
            <button class="btn btn-secondary" @onclick="RefreshShipments">🔄 Refresh</button>
        </div>
    </div>

    @if (shipments is null)
    {
        <p><em>Loading shipments...</em></p>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Description</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Description</td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString())">
                                <option value="Pending Pickup">Pending Pickup</option>
                                <option value="In Transit">In Transit</option>
                                <option value="Customs Hold">Customs Hold</option>
                                <option value="Delivered">Delivered</option>
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>

        <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
    }
</div>

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(filterText) ||
                        s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await RefreshShipments();
    }

    private async Task RefreshShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, string? newStatus)
    {
        if (!string.IsNullOrEmpty(newStatus) && newStatus != shipment.Status)
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Delivered" => "bg-success",
        "In Transit" => "bg-primary",
        "Customs Hold" => "bg-warning text-dark",
        "Pending Pickup" => "bg-info text-dark",
        _ => "bg-secondary"
    };
}
```

